// ISOLATED PROBE — remove after one execution.
// Measures whether binary crosses the Execute Workflow boundary into a sub-workflow
// on THIS n8n instance + binary storage mode. No side effects, no DB, no external calls.
let viaInput = null, viaTrigger = null, inputKeys = [], triggerKeys = [];
try { viaInput   = $input.first().binary || null; } catch (e) {}
try { viaTrigger = $('When Executed by WF-001').first().binary || null; } catch (e) {}
if (viaInput)   inputKeys   = Object.keys(viaInput);
if (viaTrigger) triggerKeys = Object.keys(viaTrigger);

let bufferOk = false, bufferLen = null, bufferErr = null;
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  bufferOk  = Buffer.isBuffer(buf) && buf.length > 0;
  bufferLen = Buffer.isBuffer(buf) ? buf.length : null;
} catch (e) { bufferErr = String(e && e.message ? e.message : e).slice(0, 300); }

// Describe the shape of binary.data without dumping the payload.
let dataDesc = null;
if (viaInput && viaInput.data) {
  const d = viaInput.data;
  dataDesc = {
    hasId:        d.id !== undefined,
    idValue:      d.id !== undefined ? String(d.id).slice(0, 60) : null,
    hasInlineData: typeof d.data === 'string',
    inlineLen:    typeof d.data === 'string' ? d.data.length : null,
    mimeType:     d.mimeType || null,
    fileName:     d.fileName || null,
    fileSize:     d.fileSize || null
  };
}

return [{ json: {
  _probe: 'binary-boundary',
  input_has_binary:          !!viaInput,
  input_binary_keys:         inputKeys,
  trigger_has_binary:        !!viaTrigger,
  trigger_binary_keys:       triggerKeys,
  data_property:             dataDesc,
  getBinaryDataBuffer_ok:    bufferOk,
  getBinaryDataBuffer_bytes: bufferLen,
  getBinaryDataBuffer_error: bufferErr,
  n8n_binary_mode_hint:      (dataDesc && dataDesc.hasId && !dataDesc.hasInlineData) ? 'filesystem/s3 (pointer)' : (dataDesc && dataDesc.hasInlineData ? 'in-memory (base64 inline)' : 'unknown')
}}];
